function useCounter(initialValue) {
  // Create a state variable called count with initialValue
  const [count, setCount] = useState(initialValue);

  // Create a function that increments count by 1
  function increment() {
    setCount(count + 1);
  }

  // Create a function that decrements count by 1
  function decrement() {
    setCount(count - 1);
  }

  // Return count, increment, and decrement
  return { count, increment, decrement };
}
